"use client"

import * as React from "react"
import {
    Plus,
    Trash2,
    Edit,
    Image as ImageIcon,
    Check,
    X,
    Loader2,
    GripVertical,
    Upload,
    Languages,
    Sparkles
} from "lucide-react"
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Badge } from "@/components/ui/badge"
import { toast } from "sonner"
import {
    createServiceCategory,
    updateServiceCategory,
    deleteServiceCategory
} from "@/app/lib/actions/service"
import { ServiceCategoryType } from "./services-table"

interface CategoryDialogProps {
    open: boolean
    onOpenChange: (open: boolean) => void
    categories: ServiceCategoryType[]
    onCategoriesChange: (categories: ServiceCategoryType[]) => void
}

export function CategoryDialog({ open, onOpenChange, categories, onCategoriesChange }: CategoryDialogProps) {
    const [editingCategory, setEditingCategory] = React.useState<ServiceCategoryType | null>(null)
    const [isFormOpen, setIsFormOpen] = React.useState(false)
    const [isSaving, setIsSaving] = React.useState(false)
    const [isUploading, setIsUploading] = React.useState(false)
    const [isTranslating, setIsTranslating] = React.useState<string | null>(null)

    const [formData, setFormData] = React.useState({
        nameEL: "",
        nameEN: "",
        descriptionEL: "",
        descriptionEN: "",
        icon: "",
        order: 0
    })

    const resetForm = () => {
        setFormData({ nameEL: "", nameEN: "", descriptionEL: "", descriptionEN: "", icon: "", order: categories.length })
        setEditingCategory(null)
    }

    const handleEdit = (cat: ServiceCategoryType) => {
        setEditingCategory(cat)
        setFormData({
            nameEL: cat.nameEL,
            nameEN: cat.nameEN || "",
            descriptionEL: cat.descriptionEL || "",
            descriptionEN: cat.descriptionEN || "",
            icon: cat.icon || "",
            order: cat.order
        })
        setIsFormOpen(true)
    }

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure? This will delete the category and all associated services.")) return
        try {
            await deleteServiceCategory(id)
            onCategoriesChange(categories.filter(c => c.id !== id))
            toast.success("Category deleted")
        } catch (err: any) {
            toast.error(err.message)
        }
    }

    const handleIconUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return
        setIsUploading(true)
        const uploadData = new FormData()
        uploadData.append("file", file)
        uploadData.append("type", "icon")

        try {
            const res = await fetch("/api/admin/services/upload", { method: "POST", body: uploadData })
            const data = await res.json()
            if (data.url) {
                setFormData(prev => ({ ...prev, icon: data.url }))
                toast.success("Icon uploaded")
            }
        } catch (err: any) {
            toast.error("Upload failed")
        } finally {
            setIsUploading(false)
        }
    }

    const handleTranslate = async (sourceField: keyof typeof formData, targetField: keyof typeof formData) => {
        const sourceValue = formData[sourceField]
        if (!sourceValue || typeof sourceValue !== 'string') {
            toast.error("Please enter some text in Greek first")
            return
        }

        setIsTranslating(String(targetField))
        try {
            const res = await fetch("/api/admin/translate", {
                method: "POST",
                body: JSON.stringify({ text: sourceValue, targetLang: "en" })
            })
            const data = await res.json()
            if (data.translated) {
                setFormData(prev => ({ ...prev, [targetField]: data.translated }))
                toast.success("Translation complete")
            } else {
                throw new Error(data.error || "Translation failed")
            }
        } catch (err: any) {
            toast.error(err.message)
        } finally {
            setIsTranslating(null)
        }
    }

    const handleSave = async () => {
        if (!formData.nameEL) return toast.error("Greek name is required")
        setIsSaving(true)
        try {
            if (editingCategory) {
                const updated = await updateServiceCategory(editingCategory.id, formData)
                onCategoriesChange(categories.map(c => c.id === updated.id ? { ...c, ...updated } : c))
                toast.success("Category updated")
            } else {
                const created = await createServiceCategory(formData)
                onCategoriesChange([...categories, created as any])
                toast.success("Category created")
            }
            setIsFormOpen(false)
            resetForm()
        } catch (err: any) {
            toast.error(err.message)
        } finally {
            setIsSaving(false)
        }
    }

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-2xl bg-white dark:bg-zinc-950 p-0 overflow-hidden rounded-2xl border-zinc-200 dark:border-zinc-800">
                <DialogHeader className="p-6 border-b border-zinc-100 dark:border-zinc-900 bg-zinc-600">
                    <div className="flex justify-between items-center">
                        <DialogTitle className="text-xl font-bold tracking-tight text-white">Service Categories</DialogTitle>
                        {!isFormOpen && (
                            <Button size="sm" onClick={() => { resetForm(); setIsFormOpen(true); }} className="bg-white text-zinc-600 hover:bg-zinc-100 font-bold border-none">
                                <Plus className="w-4 h-4 mr-2" /> New Category
                            </Button>
                        )}
                    </div>
                </DialogHeader>

                <div className="p-6">
                    {isFormOpen ? (
                        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label className="text-xs font-bold uppercase text-zinc-400">Name (Greek) *</Label>
                                    <Input value={formData.nameEL} onChange={e => setFormData({ ...formData, nameEL: e.target.value })} placeholder="e.g. ERP Solutions" />
                                </div>
                                <div className="space-y-2">
                                    <div className="flex items-center justify-between">
                                        <Label className="text-xs font-bold uppercase text-zinc-400">Name (English)</Label>
                                        <Button
                                            type="button"
                                            variant="ghost"
                                            size="sm"
                                            className="h-6 px-2 text-[10px] font-bold text-blue-600 hover:text-blue-700 hover:bg-blue-50"
                                            onClick={() => handleTranslate("nameEL", "nameEN")}
                                            disabled={!!isTranslating}
                                        >
                                            {isTranslating === "nameEN" ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <Sparkles className="w-3 h-3 mr-1" />}
                                            Translate
                                        </Button>
                                    </div>
                                    <Input value={formData.nameEN} onChange={e => setFormData({ ...formData, nameEN: e.target.value })} />
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label className="text-xs font-bold uppercase text-zinc-400">Description (Greek)</Label>
                                    <Textarea value={formData.descriptionEL} onChange={e => setFormData({ ...formData, descriptionEL: e.target.value })} placeholder="Greek description..." className="h-24" />
                                </div>
                                <div className="space-y-2">
                                    <div className="flex items-center justify-between">
                                        <Label className="text-xs font-bold uppercase text-zinc-400">Description (English)</Label>
                                        <Button
                                            type="button"
                                            variant="ghost"
                                            size="sm"
                                            className="h-6 px-2 text-[10px] font-bold text-blue-600 hover:text-blue-700 hover:bg-blue-50"
                                            onClick={() => handleTranslate("descriptionEL", "descriptionEN")}
                                            disabled={!!isTranslating}
                                        >
                                            {isTranslating === "descriptionEN" ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <Sparkles className="w-3 h-3 mr-1" />}
                                            Translate
                                        </Button>
                                    </div>
                                    <Textarea value={formData.descriptionEN} onChange={e => setFormData({ ...formData, descriptionEN: e.target.value })} className="h-24" />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label className="text-xs font-bold uppercase text-zinc-400">Icon / Thumbnail</Label>
                                <div className="flex items-center gap-4">
                                    <div className="w-16 h-16 rounded-xl border-2 border-dashed border-zinc-200 flex items-center justify-center bg-zinc-50 overflow-hidden relative group">
                                        {formData.icon ? (
                                            <>
                                                <img src={formData.icon} className="w-full h-full object-contain p-2" />
                                                <button onClick={() => setFormData({ ...formData, icon: "" })} className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center text-white transition-opacity">
                                                    <X className="w-4 h-4" />
                                                </button>
                                            </>
                                        ) : (
                                            <div className="relative">
                                                {isUploading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Upload className="w-5 h-5 text-zinc-400" />}
                                                <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={handleIconUpload} />
                                            </div>
                                        )}
                                    </div>
                                    <div className="flex-1 text-xs text-zinc-500">
                                        Upload a small SVG or PNG icon to represent this category on the website.
                                    </div>
                                </div>
                            </div>

                            <div className="flex justify-end gap-3 pt-4 border-t">
                                <Button variant="outline" size="sm" onClick={() => setIsFormOpen(false)}>Cancel</Button>
                                <Button size="sm" onClick={handleSave} disabled={isSaving} className="bg-zinc-600 text-white hover:bg-zinc-700 min-w-[100px] font-bold">
                                    {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Check className="w-4 h-4 mr-2" />}
                                    Save Category
                                </Button>
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                            {categories.map(cat => (
                                <div key={cat.id} className="flex items-center justify-between p-3 rounded-xl border border-zinc-100 dark:border-zinc-900 bg-white dark:bg-zinc-950 hover:shadow-md transition-all group">
                                    <div className="flex items-center gap-4 text-zinc-400 group-hover:text-zinc-900 cursor-grab">
                                        <GripVertical className="w-4 h-4" />
                                        <div className="w-10 h-10 rounded-lg bg-zinc-50 flex items-center justify-center overflow-hidden border">
                                            {cat.icon ? <img src={cat.icon} className="w-full h-full object-contain p-1" /> : <ImageIcon className="w-4 h-4 text-zinc-300" />}
                                        </div>
                                        <div>
                                            <span className="text-sm font-semibold text-zinc-900 dark:text-zinc-100">{cat.nameEL}</span>
                                            <Badge variant="secondary" className="ml-2 text-[10px]">{cat._count?.services || 0} services</Badge>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-1">
                                        <Button variant="ghost" size="icon" onClick={() => handleEdit(cat)} className="h-8 w-8 text-zinc-400 hover:text-zinc-900 hover:bg-zinc-50">
                                            <Edit className="w-4 h-4" />
                                        </Button>
                                        <Button variant="ghost" size="icon" onClick={() => handleDelete(cat.id)} className="h-8 w-8 text-zinc-400 hover:text-red-600 hover:bg-red-50">
                                            <Trash2 className="w-4 h-4" />
                                        </Button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </DialogContent>
        </Dialog>
    )
}
